    box-shadow: 0 4px 12px rgba(26, 86, 219, 0.15);
    transform: translateY(-2px);
}

.hero {
    text-align: left;
}

.hero-title {
    margin: 0 0 8px;
    font-size: clamp(2rem, 4vw, 2.8rem);
    line-height: 1.15;
}

.hero-tagline {
    margin: 0 0 16px;
    color: var(--muted);
    font-size: 1.05rem;
}

.feature-list {
    margin: 14px 0 0;
    padding-left: 20px;
    color: var(--text);
}

.feature-list li {
    margin: 6px 0;
}

.form-grid {
    display: grid;
    gap: 12px;
    max-width: 520px;
}

label {
    display: block;
    font-weight: 600;
    margin-bottom: 6px;
}

input,
select,
textarea {
    width: 100%;
    border: 1px solid var(--border);
    border-radius: 10px;
    padding: 10px 12px;
    font-size: 0.95rem;
    background: #fff;
}

input:focus,
select:focus,
textarea:focus {
    outline: 2px solid #bfdbfe;
    border-color: #93c5fd;
}

.btn,
button {
    appearance: none;
    border: none;
    border-radius: 10px;
    padding: 10px 14px;
    font-size: 0.92rem;
    font-weight: 600;
    cursor: pointer;
    text-decoration: none;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 6px;
}

.btn-primary,
button,
.btn {
    background: var(--primary);
    color: #fff;
}

.btn-primary:hover,
button:hover,
.btn:hover {
    background: var(--primary-hover);
}

.btn-danger {
    background: var(--danger);
    color: #fff;
}

.btn-danger:hover {
    background: var(--danger-hover);
}

.btn-warning {
    background: #d97706;
    color: #fff;
}

.btn-warning:hover {
    background: #b45309;
}

.btn-success {
    background: var(--success);
    color: #fff;
}

.btn-success:hover {
    background: var(--success-hover);
}

.btn-secondary {
    background: var(--secondary);
    color: #fff;
}

.btn-secondary:hover {
    background: var(--secondary-hover);
}

.actions {
    display: flex;
    gap: 10px;
    flex-wrap: wrap;
    margin-top: 14px;
}

table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 10px;
    overflow: hidden;
    border-radius: 10px;
}

th,
td {
    border: 1px solid var(--border);
    padding: 10px;
    text-align: left;
    vertical-align: top;
}

th {
    background: #f8fafc;
}

.admin-courses-row {
    transition: 0.15s ease;
}

.admin-courses-row:hover {
    background: #eef2ff;
}

.admin-courses-row:nth-child(even) {
    background: #f8f9fa;
}

.admin-courses-row:nth-child(even):hover {
    background: #eef2ff;
}

.error-text,
.field-error {
    color: #b91c1c;
    font-size: 0.9rem;
    margin-top: 4px;
    display: block;
}

.helper-text {
    color: var(--muted);
    font-size: 0.92rem;
}

.empty-state {
    color: var(--muted);
    background: #f8fafc;
    border: 1px dashed var(--border);
    padding: 12px;
    border-radius: 10px;
}

.success-soft {
    background: var(--success-soft);
    border: 1px solid #a7f3d0;
    border-radius: 10px;
    padding: 10px;
}

.inline-form {
    display: inline;
}

/* ========== Flash alert banners ========== */
.alert {
    padding: 12px 16px;
    border-radius: 10px;
    margin-bottom: 16px;
    font-weight: 500;
    display: flex;
    align-items: center;
    gap: 8px;
}

.alert-success {
    background: #ecfdf5;
    border: 1px solid #a7f3d0;
    color: #065f46;
}

.alert-error {
    background: #fef2f2;
    border: 1px solid #fecaca;
    color: #991b1b;
}

.alert-warning {
    background: #fffbeb;
    border: 1px solid #fde68a;
    color: #92400e;
}

.role-badge {
    display: inline-block;
    margin-left: 8px;
    padding: 3px 8px;
    border-radius: 999px;
    font-size: 0.75rem;
    vertical-align: middle;
    font-weight: 700;
}

.role-admin {
    background: #dbeafe;
    color: #1d4ed8;
}

.role-student {
    background: #dcfce7;
    color: #15803d;
}

.stats-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
    gap: 12px;
    margin: 10px 0 16px;
}

.stat-card {
    border: 1px solid var(--border);
    border-radius: 10px;
    padding: 12px;
    background: #f8fafc;
}

.stat-label {
    font-size: 0.85rem;
    color: var(--muted);
}

.stat-value {
    font-size: 1.4rem;
    font-weight: 700;
    margin-top: 4px;
}

.course-card-grid {
    display: grid;
    gap: 12px;
    grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
}

.course-student-card {
    border: 1px solid var(--border);
    border-left: 4px solid #1a56db;
    border-radius: 12px;
    padding: 14px;
    background: #fff;
    transition: 0.2s ease;
}

.course-student-card:hover {
    box-shadow: 0 8px 16px rgba(26, 86, 219, 0.15);
    transform: translateY(-2px);
}

.course-code {
    font-size: 1.15rem;
    font-weight: 800;
    margin-bottom: 6px;
    color: #1a56db;
}

.course-name {
    font-weight: 600;
    margin-bottom: 6px;
}

.course-prof {
    color: var(--muted);
    margin-bottom: 12px;
}

.btn:disabled,
button:disabled {
    opacity: 0.7;
    cursor: not-allowed;
}

.toast-container {
    position: fixed;
    top: 16px;
    right: 16px;
    display: grid;
    gap: 10px;
    z-index: 1300;
    width: min(360px, calc(100% - 24px));
}

.toast-container-auth {
    position: static;
    width: 100%;
    margin-bottom: 12px;
}

.toast {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 10px;
    padding: 12px 14px;
    border-radius: 10px;
    border: 1px solid transparent;
    box-shadow: 0 8px 20px rgba(15, 23, 42, 0.12);
    background: #fff;
}

.toast-success {
    background: #ecfdf5;
    border-color: #a7f3d0;
    color: #065f46;
}

.toast-warning {
    background: #fffbeb;
    border-color: #fde68a;
    color: #92400e;
}

.toast-error {
    background: #fef2f2;
    border-color: #fecaca;
    color: #991b1b;
}

.toast-close {
    border: none;
    background: transparent;
    color: inherit;
    font-size: 1.25rem;
    line-height: 1;
    cursor: pointer;
    padding: 0;
}

.toast-hide {
    opacity: 0;
    transform: translateY(-8px);
    transition: 0.25s ease;
}

.modal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(15, 23, 42, 0.55);
    display: none;
    align-items: center;
    justify-content: center;
    padding: 16px;
    z-index: 1400;
}

.modal-overlay.show {
    display: flex;
}

.modal-card {
    background: #fff;
    width: min(440px, 100%);
    border-radius: 12px;
    padding: 18px;
    border: 1px solid var(--border);
    box-shadow: 0 18px 36px rgba(15, 23, 42, 0.22);
}

/* ========== Active nav button ========== */
.btn.active,
a.btn.active {
    background: var(--primary);
    color: #fff;
    box-shadow: inset 0 0 0 2px rgba(0, 0, 0, 0.12);
    text-decoration: none;
}

@media (max-width: 768px) {
    .container {
        padding: 16px;
    }

    .app-header {
        flex-direction: column;
        align-items: flex-start;
    }

    .nav,
    .actions {
        width: 100%;
    }

    .nav .btn,
    .actions .btn,
    .actions button,
    .form-grid button {
        width: 100%;
    }

    th,
    td {
        font-size: 0.9rem;
    }
}

package org.university.api;

import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.mock.web.MockHttpSession;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContext;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.web.context.HttpSessionSecurityContextRepository;
import org.springframework.test.web.servlet.MockMvc;
import org.university.model.Course;
import org.university.repo.CourseRepository;

import java.util.List;
import java.util.Optional;

import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.*;
import static org.springframework.http.MediaType.APPLICATION_JSON;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.status;

@SpringBootTest(properties = {
        "spring.profiles.active=dev",
        "spring.jpa.hibernate.ddl-auto=create-drop"
})
@AutoConfigureMockMvc
class CourseApiControllerTest {

    @Autowired
    private MockMvc mockMvc;

    @MockBean
    private CourseRepository courseRepository;

    @Test
    void get_courses_returns_200_when_authenticated() throws Exception {
        when(courseRepository.findAll()).thenReturn(
                List.of(new Course("CS612", "Web Services", "Prof. X"))
        );

        mockMvc.perform(get("/api/v1/courses")
                        .session(authenticatedSession("student1", "STUDENT")))
                .andExpect(status().isOk());
    }

    @Test
    void get_courses_returns_401_when_not_authenticated() throws Exception {
        mockMvc.perform(get("/api/v1/courses")
                        .header("X-Requested-With", "XMLHttpRequest"))
                .andExpect(status().isUnauthorized());
    }

    @Test
    void get_course_by_id_returns_404_for_non_existent_course() throws Exception {
        when(courseRepository.findById(999L)).thenReturn(Optional.empty());

        mockMvc.perform(get("/api/v1/courses/999")
                        .session(authenticatedSession("student1", "STUDENT")))
                .andExpect(status().isNotFound());
    }

    @Test
    void post_course_returns_403_when_student_tries_to_create() throws Exception {
        String payload = """
                {
                  \"code\": \"CS999\",
                  \"name\": \"Distributed Systems\",
                  \"professor\": \"Prof. Z\"
                }
                """;

        mockMvc.perform(post("/api/v1/courses")
                        .contentType(APPLICATION_JSON)
                        .content(payload)
                        .session(authenticatedSession("student1", "STUDENT")))
                .andExpect(status().isForbidden());

        verify(courseRepository, never()).save(any(Course.class));
    }

    private MockHttpSession authenticatedSession(String username, String role) {
        Authentication authentication = new UsernamePasswordAuthenticationToken(
                username,
                "N/A",
                List.of(new SimpleGrantedAuthority("ROLE_" + role))
        );

        SecurityContext context = SecurityContextHolder.createEmptyContext();
        context.setAuthentication(authentication);

        MockHttpSession session = new MockHttpSession();
        session.setAttribute(HttpSessionSecurityContextRepository.SPRING_SECURITY_CONTEXT_KEY, context);
        return session;
    }
}

package org.university.dto;

import jakarta.validation.ConstraintViolation;
import jakarta.validation.Validation;
import jakarta.validation.Validator;
import jakarta.validation.ValidatorFactory;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

import java.util.Set;

import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

class RegisterRequestValidationTest {

    private static Validator validator;

    @BeforeAll
    static void setupValidator() {
        ValidatorFactory factory = Validation.buildDefaultValidatorFactory();
        validator = factory.getValidator();
    }

    @Test
    void valid_request_passes_validation() {
        RegisterRequest request = buildRequest("student1", "Strong@123", "Strong@123");

        Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);

        assertTrue(violations.isEmpty());
    }

    @Test
    void blank_username_fails_validation() {
        RegisterRequest request = buildRequest("   ", "Strong@123", "Strong@123");

        Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);

        assertTrue(violations.stream().anyMatch(v ->
                "username".equals(v.getPropertyPath().toString())
                        && "Username is required".equals(v.getMessage())));
    }

    @Test
    void blank_password_fails_validation() {
        RegisterRequest request = buildRequest("student1", "", "Strong@123");

        Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);

        assertTrue(violations.stream().anyMatch(v ->
                "password".equals(v.getPropertyPath().toString())
                        && "Password is required".equals(v.getMessage())));
    }

    @Test
    void weak_password_fails_StrongPassword() {
        RegisterRequest request = buildRequest("student1", "weakpass", "weakpass");

        Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);

        assertTrue(violations.stream().anyMatch(v ->
                "password".equals(v.getPropertyPath().toString())
                        && v.getMessage().contains("Password must be at least 8 characters")));
    }

    @Test
    void strong_password_passes_StrongPassword() {
        RegisterRequest request = buildRequest("student1", "Aa1@abcd", "Aa1@abcd");

        Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);

        assertFalse(violations.stream().anyMatch(v ->
                "password".equals(v.getPropertyPath().toString())
                        && v.getMessage().contains("Password must be at least 8 characters")));
    }

    private RegisterRequest buildRequest(String username, String password, String confirmPassword) {
        RegisterRequest request = new RegisterRequest();
        request.setUsername(username);
        request.setPassword(password);
        request.setConfirmPassword(confirmPassword);
        return request;
    }
}

package org.university.service;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.ArgumentCaptor;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.context.ApplicationEventPublisher;
import org.springframework.test.util.ReflectionTestUtils;
import org.university.event.EnrollmentEvent;
import org.university.model.AppUser;
import org.university.model.Course;
import org.university.model.Enrollment;
import org.university.repo.AppUserRepository;
import org.university.repo.CourseRepository;
import org.university.repo.EnrollmentRepository;

import java.util.Optional;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)
class EnrollmentServiceTest {

    @Mock
    private EnrollmentRepository enrollmentRepository;

    @Mock
    private CourseRepository courseRepository;

    @Mock
    private AppUserRepository appUserRepository;

    @Mock
    private ApplicationEventPublisher applicationEventPublisher;

    @InjectMocks
    private EnrollmentService enrollmentService;

    @Test
    void enroll_success() {
        AppUser student = new AppUser("student1", "hash", "STUDENT");
        ReflectionTestUtils.setField(student, "id", 100L);

        Course course = new Course("CS612", "Web Services", "Prof. X");
        ReflectionTestUtils.setField(course, "id", 10L);

        when(appUserRepository.findByUsername("student1")).thenReturn(Optional.of(student));
        when(courseRepository.findById(10L)).thenReturn(Optional.of(course));
        when(enrollmentRepository.existsByStudentIdAndCourseId(100L, 10L)).thenReturn(false);

        enrollmentService.enroll("student1", 10L);

        ArgumentCaptor<Enrollment> enrollmentCaptor = ArgumentCaptor.forClass(Enrollment.class);
        verify(enrollmentRepository).save(enrollmentCaptor.capture());
        Enrollment saved = enrollmentCaptor.getValue();
        assertEquals(student, saved.getStudent());
        assertEquals(course, saved.getCourse());

        verify(applicationEventPublisher).publishEvent(any(EnrollmentEvent.class));
    }

    @Test
    void enroll_throwsWhenAlreadyEnrolled() {
        AppUser student = new AppUser("student1", "hash", "STUDENT");
        ReflectionTestUtils.setField(student, "id", 100L);

        Course course = new Course("CS612", "Web Services", "Prof. X");
        ReflectionTestUtils.setField(course, "id", 10L);

        when(appUserRepository.findByUsername("student1")).thenReturn(Optional.of(student));
        when(courseRepository.findById(10L)).thenReturn(Optional.of(course));
        when(enrollmentRepository.existsByStudentIdAndCourseId(100L, 10L)).thenReturn(true);

        assertThrows(IllegalStateException.class, () -> enrollmentService.enroll("student1", 10L));

        verify(enrollmentRepository, never()).save(any(Enrollment.class));
        verify(applicationEventPublisher, never()).publishEvent(any());
    }

    @Test
    void enroll_throwsWhenCourseNotFound() {
        AppUser student = new AppUser("student1", "hash", "STUDENT");
        ReflectionTestUtils.setField(student, "id", 100L);

        when(appUserRepository.findByUsername("student1")).thenReturn(Optional.of(student));
        when(courseRepository.findById(999L)).thenReturn(Optional.empty());

        assertThrows(IllegalArgumentException.class, () -> enrollmentService.enroll("student1", 999L));

        verify(enrollmentRepository, never()).save(any(Enrollment.class));
        verify(applicationEventPublisher, never()).publishEvent(any());
    }

    @Test
    void drop_success() {
        AppUser student = new AppUser("student1", "hash", "STUDENT");
        ReflectionTestUtils.setField(student, "id", 100L);

        Course course = new Course("CS612", "Web Services", "Prof. X");
        ReflectionTestUtils.setField(course, "id", 10L);

        Enrollment enrollment = new Enrollment(student, course);

        when(appUserRepository.findByUsername("student1")).thenReturn(Optional.of(student));
        when(enrollmentRepository.findByStudentIdAndCourseId(100L, 10L)).thenReturn(Optional.of(enrollment));

        enrollmentService.drop("student1", 10L);

        verify(enrollmentRepository).delete(enrollment);
        verify(applicationEventPublisher).publishEvent(any(EnrollmentEvent.class));
    }

    @Test
    void drop_throwsWhenEnrollmentNotFound() {
        AppUser student = new AppUser("student1", "hash", "STUDENT");
        ReflectionTestUtils.setField(student, "id", 100L);

        when(appUserRepository.findByUsername("student1")).thenReturn(Optional.of(student));
        when(enrollmentRepository.findByStudentIdAndCourseId(100L, 99L)).thenReturn(Optional.empty());

        assertThrows(IllegalStateException.class, () -> enrollmentService.drop("student1", 99L));

        verify(enrollmentRepository, never()).delete(any(Enrollment.class));
        verify(applicationEventPublisher, never()).publishEvent(any());
    }
}
